#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);set<long long>seen;seen.insert(0);long long s=0;bool ok=false;for(int i=0;i<n;i++){long long x;scanf("%lld",&x);s+=x;if(seen.count(s))ok=true;seen.insert(s);}puts(ok?"YES":"NO");}
